select id, tenant_id, username, display_name, authorities_csv, enabled, created_at, updated_at
from batch.console_user_account


        and tenant_id = #{tenantId}


        and (username ilike concat('%', #{keyword}, '%')
          or display_name ilike concat('%', #{keyword}, '%'))


order by id desc


    limit #{pageRequest.pageSize}
    offset #{offset}

